   172	    public void mergeShards(String streamName, String shardId, String adjacentShardId, String region) {
   173	        KinesisStream stream = resolveStream(streamName, region);
   174	        KinesisShard shard1 = stream.getShards().stream()
   175	                .filter(s -> s.getShardId().equals(shardId))
   176	                .findFirst()
   177	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Shard " + shardId + " not found", 400));
   178	        KinesisShard shard2 = stream.getShards().stream()
   179	                .filter(s -> s.getShardId().equals(adjacentShardId))
   180	                .findFirst()
   181	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Shard " + adjacentShardId + " not found", 400));
   182	
   183	        if (shard1.isClosed() || shard2.isClosed()) {
   184	            throw new AwsException("InvalidArgumentException", "One or both shards are already closed", 400);
   185	        }
   186	
   187	        shard1.setClosed(true);
   188	        shard2.setClosed(true);
   189	        String seq = String.valueOf(sequenceGenerator.get());
   190	        shard1.setSequenceNumberRange(new KinesisShard.SequenceNumberRange(shard1.getSequenceNumberRange().startingSequenceNumber(), seq));
   191	        shard2.setSequenceNumberRange(new KinesisShard.SequenceNumberRange(shard2.getSequenceNumberRange().startingSequenceNumber(), seq));
   192	
   193	        // Combine hash ranges (assuming they are adjacent)
   194	        java.math.BigInteger s1Start = new java.math.BigInteger(shard1.getHashKeyRange().startingHashKey());
   195	        java.math.BigInteger s2Start = new java.math.BigInteger(shard2.getHashKeyRange().startingHashKey());
   196	        
   197	        String start = s1Start.min(s2Start).toString();
   198	        java.math.BigInteger s1End = new java.math.BigInteger(shard1.getHashKeyRange().endingHashKey());
   199	        java.math.BigInteger s2End = new java.math.BigInteger(shard2.getHashKeyRange().endingHashKey());
   200	        String end = s1End.max(s2End).toString();
   201	
   202	        KinesisShard child = new KinesisShard(nextShardId(stream), start, end, seq);
   203	        child.setParentShardId(shardId);
   204	        child.setAdjacentParentShardId(adjacentShardId);
   205	
   206	        stream.getShards().add(child);
   207	        store.put(regionKey(region, streamName), stream);
   208	        LOG.infov("Merged shards {0} and {1} in stream {2}", shardId, adjacentShardId, streamName);
   209	    }
