   232	    public String getShardIterator(String streamName, String shardId, String type, String sequenceNumber, String region) {
   233	        resolveStream(streamName, region); // validate exists
   234	        // Format: streamName|shardId|type|sequenceNumber|index
   235	        String raw = String.format("%s|%s|%s|%s|%d", 
   236	                streamName, shardId, type, sequenceNumber != null ? sequenceNumber : "", 0);
   237	        return Base64.getEncoder().encodeToString(raw.getBytes(StandardCharsets.UTF_8));
