   240	    public Map<String, Object> getRecords(String shardIterator, Integer limit, String region) {
   241	        byte[] decoded = Base64.getDecoder().decode(shardIterator);
   242	        String[] parts = new String(decoded, StandardCharsets.UTF_8).split(java.util.regex.Pattern.quote("|"), 5);
   243	        if (parts.length < 5) throw new AwsException("InvalidArgumentException", "Invalid shard iterator", 400);
   244	
   245	        String streamName = parts[0];
   246	        String shardId = parts[1];
   247	        String type = parts[2];
   248	        String startSeq = parts[3];
   249	        int lastIndex = Integer.parseInt(parts[4]);
   250	
   251	        KinesisStream stream = resolveStream(streamName, region);
   252	        KinesisShard shard = stream.getShards().stream()
   253	                .filter(s -> s.getShardId().equals(shardId))
   254	                .findFirst()
   255	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Shard not found", 400));
   256	
   257	        List<KinesisRecord> allRecords = shard.getRecords();
   258	        int startIndex = 0;
   259	
   260	        // Simple implementation of iterator types
   261	        if ("TRIM_HORIZON".equals(type)) {
   262	            startIndex = lastIndex;
   263	        } else if ("LATEST".equals(type)) {
   264	            startIndex = allRecords.size();
   265	        } else if ("AT_SEQUENCE_NUMBER".equals(type)) {
   266	            for (int i = 0; i < allRecords.size(); i++) {
   267	                if (allRecords.get(i).getSequenceNumber().equals(startSeq)) {
   268	                    startIndex = i;
   269	                    break;
   270	                }
   271	            }
   272	        } else if ("AFTER_SEQUENCE_NUMBER".equals(type)) {
   273	             for (int i = 0; i < allRecords.size(); i++) {
   274	                if (allRecords.get(i).getSequenceNumber().equals(startSeq)) {
   275	                    startIndex = i + 1;
   276	                    break;
   277	                }
   278	            }
   279	        }
   280	
   281	        int max = limit != null ? Math.min(limit, 1000) : 1000;
   282	        List<KinesisRecord> result = new ArrayList<>();
   283	        int nextIndex = startIndex;
   284	        for (int i = startIndex; i < allRecords.size() && result.size() < max; i++) {
   285	            result.add(allRecords.get(i));
   286	            nextIndex = i + 1;
   287	        }
   288	
   289	        String nextIterator = Base64.getEncoder().encodeToString(
   290	                String.format("%s|%s|%s|%s|%d", streamName, shardId, "TRIM_HORIZON", "", nextIndex)
   291	                .getBytes(StandardCharsets.UTF_8));
   292	
   293	        Map<String, Object> response = new HashMap<>();
   294	        response.put("Records", result);
   295	        response.put("NextShardIterator", nextIterator);
   296	        response.put("MillisBehindLatest", Math.max(0, allRecords.size() - nextIndex));
   297	        return response;
   298	    }
