   300	    private KinesisStream resolveStream(String streamName, String region) {
   301	        return store.get(regionKey(region, streamName))
   302	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Stream " + streamName + " not found", 400));
   303	    }
