   305	    private KinesisShard selectShard(KinesisStream stream, String partitionKey) {
   306	        // Simple hash-based shard selection among ALL shards, then resolve to open one
   307	        int index = Math.abs(partitionKey.hashCode()) % stream.getShards().size();
   308	        KinesisShard shard = stream.getShards().get(index);
   309	        
   310	        // If closed, find the first open child (simplified)
   311	        while (shard.isClosed()) {
   312	            KinesisShard finalShard = shard;
   313	            shard = stream.getShards().stream()
   314	                    .filter(s -> finalShard.getShardId().equals(s.getParentShardId()) || finalShard.getShardId().equals(s.getAdjacentParentShardId()))
   315	                    .filter(s -> !s.isClosed())
   316	                    .findFirst()
   317	                    .orElse(shard); // Fallback to itself if no open child found
   318	            if (shard == finalShard) break; // prevent infinite loop
   319	        }
   320	        return shard;
   321	    }
   322	
   323	    private String regionKey(String region, String name) {
   324	        return region + "::" + name;
   325	    }
