import io.github.hectorvent.floci.core.common.AwsException;
import io.github.hectorvent.floci.core.common.RegionResolver;
import io.github.hectorvent.floci.core.storage.InMemoryStorage;
import io.github.hectorvent.floci.services.kinesis.KinesisService;
import io.github.hectorvent.floci.services.kinesis.model.KinesisStream;

public class ReproTest {
    public static void main(String[] args) {
        KinesisService service = new KinesisService(
                new InMemoryStorage<>(),
                new InMemoryStorage<>(),
                new RegionResolver("us-east-1", "000000000000")
        );

        String region = "us-east-1";
        KinesisStream stream = service.createStream("test-stream", 1, region);
        System.out.println("Default retention: " + stream.getRetentionPeriodHours() + "h");

        // Increase from 24 to 48 - should work
        service.increaseStreamRetentionPeriod("test-stream", 48, region);
        System.out.println("After increase to 48h: OK");

        // Increase from 48 to 48 (same value) - should be no-op per real AWS
        try {
            service.increaseStreamRetentionPeriod("test-stream", 48, region);
            System.out.println("Same-value increase (48->48): OK (no-op) - FIX WORKING");
        } catch (AwsException e) {
            System.out.println("Same-value increase (48->48): FAILED - " + e.getMessage());
        }

        // Increase from 24 to 24 (default same value) - should be no-op
        try {
            service.increaseStreamRetentionPeriod("test-stream", 24, region);
            System.out.println("Same-value increase (24 after 48): FAILED - should NOT succeed (24 < 48)");
        } catch (AwsException e) {
            System.out.println("Same-value increase (24 after 48): OK error - " + e.getMessage());
        }
    }
}
